SELECT file_size
FROM model_documents
WHERE doc_id = 0;

SELECT MAX(file_size) AS largest_document_size
FROM model_documents
WHERE model_id = 0;

SELECT COUNT(*) AS config_count
FROM model_configs
WHERE model_id = 0 AND config_type = 'hyperparameter';

SELECT experiment_name
     FROM experiments
     WHERE (strftime('%s', ended_at) - strftime('%s', started_at)) = (
       SELECT MAX(strftime('%s', ended_at) - strftime('%s', started_at))
       FROM experiments
     );

SELECT data_source
FROM model_external_data
WHERE created_at >= '2023-01-01 00:00:00' AND created_at < '2023-02-01 00:00:00';
